var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후, 좋아. 이면카카오에 이 메탄올을 혼합하면…… 완벽해!","JPN":"ふふ、いいぞ。裏世界カカオにこのメタノールを混ぜると……完璧！","ENG":"Heh heh, good. Now mix the Counterside cacao with methanol... and it’s perfect!","TWN":"嘿嘿，在異界可可亞裡面加入甲醇，再攪一攪……完美！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"히익, 초콜릿에 그런 걸 넣어요? 역시 수상했어! 목적은 독살인 거죠?","JPN":"へっ、チョコレートにそんなものを入れるんですか？　やっぱり怪しい！　目的は毒殺ですか？","ENG":"You’re putting that thing into the chocolate? I knew something was fishy! You’re trying to poison someone, right?","TWN":"唔！在巧克力裡加入那種東西？果然很詭異！你是想下毒吧？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아뇨, 제가 초콜릿을 드리려는 분은 신체기관이 조금 남달라서요.","JPN":"いいえ、私がチョコレートを差し上げたい方は身体器官が少し特別なんです。","ENG":"It’s not that. The person I’m giving this chocolate is a bit different from others.","TWN":"不是的，是因為我想送巧克力給他的對象，身體構造異於常人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아니, 아무리 식성이 독특하다고 해도 이런 건 로봇이 아닌 이상…… ","JPN":"いや、いくら好みが変わっているとしても、こんなのはロボットじゃない以上…… ","ENG":"Well, I don’t think anyone will be able to eat it unless they are a robot...","TWN":"我不信！就算他的口味再怎麼特別，除非他是機器人否則…… "},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"설마 코핀 컴퍼니의 그 로봇 사장님한테 초콜릿을 선물하려는 건가요?","JPN":"まさかコフィンカンパニーのあのロボット社長にチョコレートをプレゼントするつもりですか？","ENG":"Did you make that chocolate for the robot CEO of the Coffin Company?","TWN":"難道你要送巧克力的對象，就是科芬公司的那個機器人老闆？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"흥, 당신이 선배님과 저의 정신적인 사랑을 이해할 거라고 기대하진 않아요.","JPN":"ふん、あなたが先輩と私のプラトニックな愛を理解してくれるとは期待していません。","ENG":"Hmpf, I don’t expect you to understand our platonic love.","TWN":"嗯，我不期待你理解我和老闆之間柏拉圖式的愛情。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"사랑……? 혹시 이 초콜렛으로 고백하시려고요?","JPN":"愛……？　もしかしてこのチョコレートで告白するつもりですか？","ENG":"Love? You’re planning to confess your love with this chocolate?","TWN":"愛情……？你是想用這個巧克力告白喔？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"맞아요. 그게 이상한가요?","JPN":"はい、おかしいですか？","ENG":"Yes. Something wrong?","TWN":"對啊，很奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"도와준 건 고맙지만, 우리의 사랑을 모욕할 셈이라면 나도 가만히 있지 않겠어요.","JPN":"助けてくれたのはありがたいけど、私たちの愛を侮辱するつもりなら許しません。","ENG":"I appreciate your help, but I’m not going to just sit back and take your insult, if that is your intention.","TWN":"我很感謝你的幫忙，但如果你敢嘲笑我們的愛情，我是不會放過你的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 전 대부분의 사랑을 지지하는 편이긴 한데 말이죠…….","JPN":"いいえ。私はほとんどの愛を支持する方ではありますけど……","ENG":"No, I do celebrate every type of love...","TWN":"放心吧，我通常是支持愛情的……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"제가 알고 있는 <color=#ffd34c>껄끄러운 비밀</color>을 고객님께서도 알아두는 편이 좋을 것 같아서요.","JPN":"私が知っている<color=#ffd34c>知られちゃまずい秘密</color>をお客様も知っておいたほうがいいと思いまして。","ENG":"But I think you should know this <color=#ffd34c>uncomfortable truth</color> first.","TWN":"只是有些<color=#ffd34c>你不知道的事</color>，你還是知道一下比較好。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"……?!","JPN":"……！？","ENG":"...?!","TWN":"……？！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"……!!","JPN":"……！！","ENG":"...!!","TWN":"……！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어, 어라? 방금까지 여기 있었는데?","JPN":"あ、あれ？　さっきまでここにいたのに？","ENG":"Huh? He was right here a moment ago!","TWN":"嗯？剛剛不是還在這裡嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어디로 사라지신 거지?","JPN":"どこに消えたの？","ENG":"Where did he go?","TWN":"跑哪去了？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_Q","text":{"KOREA":"누가 내 뒤를 밟고 있나 했더니 자네로군.","JPN":"誰かが私の跡を追っているかと思ったら、君だったんだね。","ENG":"So, it was you who was following me.","TWN":"我想說是誰跟在我後面，原來是你喔？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"언제까지 그렇게 따라다닐 셈이지, 후배님?","JPN":"いつまで追いかける気かね、後輩くん。","ENG":"But how much further, Lone?","TWN":"隆利，你是想跟到什麼時候？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하하…… 안녕하세요, 선배님?","JPN":"ハハ……こんにちは、先輩。","ENG":"Hah hah... Hello, Dark.","TWN":"哈哈……前輩好。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"주민들이 음산한 분위기의 여자가 몰래 숨어 다닌다며 걱정하고 있다네.","JPN":"住民たちが、陰惨な雰囲気の女性がこっそり隠れていると心配しているらしい。","ENG":"The villagers were worried about a creepy woman sneaking around.","TWN":"大家都在說有的陰沉的女生鬼鬼祟祟的，心裡很不安呢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"어째서 날 미행하던 건가?","JPN":"どうして私を尾行していたんだ？","ENG":"Why did you do that?","TWN":"你跟著我要做什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그게…… 마음먹는 건 쉬웠는데, 막상 실행으로 옮기려니 몸이 굳어버려서……","JPN":"それが……決心するのは簡単だったけど、実際に実行に移そうとしようとしたら体が固まってしまって……","ENG":"Um... I thought I had the courage, but when I actually saw you, I couldn’t do it...","TWN":"那個……雖然已經下定決心，但真的要付諸行動時，身體卻不聽使喚呢……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"실행? 또 뭔가 사악한 음모라도 꾸미고 있던 건가?","JPN":"実行？　また何か悪い陰謀でも企んでいたのか？","ENG":"Couldn't do what? Are you planning another heinous crime?","TWN":"付諸行動？你又再動什麼歪腦筋嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아, 아니에요! 저는 그러니까……!","JPN":"ち、違います！　私は……！","ENG":"N-no! I...","TWN":"沒…沒有啦！我只是……！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이걸…… 선배님께 드리고 싶어서요.","JPN":"これを……先輩に渡したくて。","ENG":"I... wanted to give you this.","TWN":"這個……送你！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"음? 이건 초콜릿이군?","JPN":"うむ？　これはチョコレートだな！","ENG":"Oh? Chocolate?","TWN":"嗯？這是巧克力？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"게다가 델리케잇한 직사각형은 마치 날 형상화한 것 같은걸?","JPN":"それにそのデリケートな長方形はまるで私のようだ。","ENG":"And this delicate cube shape looks almost like me!","TWN":"而且還是精密的四角形，這巧克力長得好像我喔？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후, 역시 알아봐주시는군요.","JPN":"ふふ、さすが気付いてくれるんですね。","ENG":"Heh heh, you do recognize it.","TWN":"呵呵，前輩果然懂我。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"혹시 이번에도 초콜릿이 괴물로 변하진 않겠지?","JPN":"さすがに今回もチョコレートが化物に変わることはないんだな？","ENG":"It’s not going to turn into a monster this time, is it?","TWN":"這次的巧克力應該不會變成怪物吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님이 원하신다면 그런 것도 얼마든지 만들어드릴 수 있고 말고요.","JPN":"先輩が望むなら、そういうものだっていくらでも作れますよ。","ENG":"I can make one if you want.","TWN":"前輩喜歡的話，那種巧克力要多少我都可以做給你。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하지만 이건 오로지 선배님을 위해 제가 개발한 선물이랍니다.","JPN":"でも、これはたった一人、先輩のために私が開発したプレゼントです。","ENG":"But this is a gift that I made just for you.","TWN":"但這個是專為前輩開發的禮物。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>친환경 바이오디젤 초콜릿</color>이에요.","JPN":"<color=#ffd34c>環境にやさしいバイオディーゼルチョコレート</color>です。","ENG":"It’s <color=#ffd34c>environment-friendly biodiesel chocolate</color>.","TWN":"這是<color=#ffd34c>環保生質柴油巧克力</color>！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"호오, 그거 구미가 당기는구만.","JPN":"ほう、それは興味深い話だな。","ENG":"Oh, that sounds delightful.","TWN":"喔呵！聽起來好像不錯喔！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"지금 하나 먹어봐도 되겠나?","JPN":"今一つ食べてみてもいいか？","ENG":"May I try?","TWN":"我可以吃一個看看嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아아, 물론이죠! 마음껏 드세요, 선배님!","JPN":"ああ、もちろんです！　好きなだけ召し上がってください、先輩！","ENG":"Oh, sure! Help yourself!","TWN":"當然可以！這些都是給前輩的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"전 말이죠.","JPN":"私はですね。","ENG":"You know...","TWN":"我想跟前輩說，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님과 만난 지금이 가장 행복해요.","JPN":"先輩と話している今が一番幸せです。","ENG":"This is the happiest time of my life, being with you.","TWN":"能夠遇到前輩是我此生最幸福的事。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님은 어째서 이렇게 멋지신 거죠?","JPN":"先輩はどうしてそんなに素敵なんですか？","ENG":"Why are you so cool?","TWN":"前輩為什麼這麼帥？？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하하, 나도 론 리 양은 참 매력적인 사람이라고 생각한다네.","JPN":"ハハハ、私もローン・リー、君はとても魅力的な人だと思うよ。","ENG":"Hah hah, I think you’re a charming woman, Lone.","TWN":"哇哈哈，我也覺得隆利是個很有魅力的人喔。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"어째서 지금껏 홀로 지내왔는지 이해가 되지 않을 정도로 말이야.","JPN":"どうして今まで恋人がいなかったのか理解できないくらいね。","ENG":"I don’t really understand why you’ve been alone for all your life.","TWN":"怎麼會到現在還是孤家寡人呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어릴 적엔, 남자 같다는 말을 듣고 머릴 길렀어요.","JPN":"幼い頃は、男みたいと言われて髪を伸ばしていました。","ENG":"When I was young, people told me I looked like a boy so I grew my hair.","TWN":"小的時候，有人說我像男生，我就把頭髮留長。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"뾰족한 이빨이 무섭대서 입 닫고 웃는 법도 연습했고요.","JPN":"尖った歯が怖いと言われて、口を閉じて笑うように練習しました。","ENG":"People said my sharp teeth were scary so I practiced to smile with my mouth closed.","TWN":"有人說虎牙很可怕，我就練習不露齒笑。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"수제 초콜릿을 거절하는 남자는 없다고 해서 시도도 해봤어요.","JPN":"手作りチョコレートを断る男はいないと聞いて、試したこともあります。","ENG":"People also said that men like hand-made chocolate, so I tried.","TWN":"有人說沒有男生會拒絕手工巧克力，我就學習做巧克力。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그런데…….","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그렇게 한다고 해서 삶이 원하는 대로 바뀌진 않더라고요.","JPN":"でも、努力したって、人生が望む方向にいくことはありませんでした。","ENG":"No matter how hard I tried, things didn’t turn out as I expected.","TWN":"我的人生並沒有因此而改變。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"쭉 혼자일 운명이라고 생각했던 제 앞에…… ","JPN":"ずっとぼっちの運命だと思っていた私の前に……","ENG":"When I gave up hope and thought I was going to die alone...","TWN":"我一直以為我就會這樣孤老終身，直到…… "},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님이 나타나셨어요.","JPN":"先輩が現れたんです。","ENG":" you came into my life.","TWN":" 前輩出現在我的生命中！"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"무슨 노력을 해도 사랑받지 못했는데…….","JPN":"どんな努力をしても愛されなかったのに……","ENG":"I tried so hard, and no one loved me...","TWN":"不管我怎麼努力就是得不到愛情……"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님은 제가 어떤 사람인지 모두 듣고서도 변함없이 절 사랑으로 감싸주셨죠.","JPN":"先輩は私がどんな人間なのか全部知ったうえで、変わらず私を愛で包んでくれました。","ENG":"Yet you loved me knowing what I really am.","TWN":"但前輩不管別人怎麼說我，還是用愛包容我。"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아시겠어요? 저에겐 선배님뿐이라는 걸요.","JPN":"わかりますか？　私には先輩しかいないことを。","ENG":"Do you understand? You’re the only one I have.","TWN":"前輩應該知道吧？你就是我的唯一。"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그래, 자네도 날 만나기 전까지 꽤나 기구한 사연이 있었군.","JPN":"そうか、私に会う前にそんな悲しい過去があったんだな。","ENG":"Yes, I see you had a hard time in the past.","TWN":"嗯嗯，原來你在遇到我之前這麼坎坷。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"마음은 이해하지만, 언제까지고 나에게 의지해선 곤란하다네.","JPN":"気持ちは分かるが、いつまでも私に頼ってもらっては困る。","ENG":"I understand your feelings, but you can’t lean on me forever.","TWN":"我明白你的心情，但你總不能一直倚靠我啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님은…… 제가 곁에 있는 게 싫으신 건가요?","JPN":"先輩は……私がそばにいるのが嫌なんですか?","ENG":"Dark, don’t you want me... by your side?","TWN":"前輩……你不喜歡我在你身邊嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그런 뜻이 아닐세.","JPN":"そういう意味ではない。","ENG":"It’s not that.","TWN":"我不是這個意思。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"전에도 말했다시피, 나 같은 떠돌이 악당은 결코 한 곳에 머물지 않거든.","JPN":"前にも言ったが、私のようなさすらいの悪党は決して一ヵ所に留まらない。","ENG":"Like I said before, I’m a wandering villain and I don’t stay in one place.","TWN":"之前我也跟你提過，像我這種浪子，是不會為誰而停留的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그럼 제가 선배님을 따라갈게요! 거기가 지옥이라고 해도 전 쫓아갈 수 있어요!","JPN":"なら私が先輩について行きます！　たとえ地獄だとしても、追いかける覚悟はできています！","ENG":"Then I’ll come with you! I’ll even follow you to hell!","TWN":"那我就嫁機隨機！就算前輩要去地獄，我也會跟著你去！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하, 그건 사양하지. 아직 거기까지 갈 계획은 없으니까.","JPN":"ハハハ、それは遠慮しておこう。まだ地獄に行く計画はないからな。","ENG":"Hah hah, that won’t be necessary. I don’t intend to go there anytime soon.","TWN":"哈哈，那倒不用，我還沒有要去地獄的打算。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"난 그저, 후배님이 평생 어미새를 따르지 않고 자신만의 날개를 펼치길 바라는 마음인 것뿐일세.","JPN":"私はただ、後輩が一生を親鳥に囚われず、自分の翼を広げて飛んでいくことを願うばかりだ。","ENG":"All I want for you is to spread your wings and fly on your own, without my help.","TWN":"我不想一直當你的保母，我希望你可以有展翅高飛的一天。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"자네라면, 내 마음을 이해해주겠지?","JPN":"君なら、私の気持ちを理解してくれるな？","ENG":"You understand me, don’t you?","TWN":"你可以明白我的意思吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"역시…….","JPN":"やっぱり……","ENG":"You’re saying this because...","TWN":"前輩……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":" 딸이 있기 때문인 거죠?","JPN":"娘がいるからですね？","ENG":" you have a daughter, right?","TWN":" 是因為女兒的關係對吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그래, 이해해줘서 고맙군. 그럼 난 이만","JPN":"そうか、わかってくれたようで助かる。それじゃ……","ENG":"Yes, thank you for understanding. Bye now","TWN":"沒錯，謝謝你的體諒，那我先走囉！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"…… 음?","JPN":"……え？","ENG":"... Huh?","TWN":"……嗯？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_SNIPER_FIRE_BIG"},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"알고 있어요! 숨겨진 자식이 있어서 절 받아들이기 어려우신 거잖아요, 그렇죠?!","JPN":"知っていますよ！　隠し子がいるから私を受け入れるのが難しいんですね？","ENG":"I knew it all along! You have a child, that’s why you can’t take me with you. Right?","TWN":"我明白！前輩是因為在外面有私生女，才不能接受我對吧？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"괜찮아요, 선배님! 선배님께 아들딸이 셋씩 있다고 해도 전 받아들일 수 있으니까요!","JPN":"大丈夫です、先輩！　先輩に息子と娘が3人ずついたとしても、私は受け入れる準備ができていますから！","ENG":"It’s okay! I’m okay even if you have three sons and three daughters!","TWN":"沒關係的！就算前輩在外面有十個八個私生子，我也可以接受！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"쿨럭…….","JPN":"ゴホッ……","ENG":"*Cough*","TWN":"唔……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_07"},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"무슨 소린지 모르겠군. 혹시 자네도 이 초콜릿을 먹은 건가?","JPN":"何を言ってるのかさっぱりだな。もしかして君もこのチョコレートを食べたのか？","ENG":"I don’t understand what you’re talking about. Did you eat this chocolate, too?","TWN":"我聽不太懂你在說什麼，你也有吃這個巧克力嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"제가 듣고 싶은 건 그런 자질구레한 변명 같은 게 아니에요.","JPN":"私が聞きたいのは、そんな話を逸らすための質問ではありません。","ENG":"I don’t want any excuses.","TWN":"我想聽的不是那些有的沒的藉口！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님이 정말로 저를 어떻게 생각하는지 듣고 싶다고요!","JPN":"先輩が本当は私のことをどう思っているのか聞きたいんです！","ENG":"What I want is the answer! Of how you think about me!","TWN":"我想知道，前輩你到底是怎麼看我的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그, 그런…….","JPN":"そ、そんな……","ENG":"Th-that’s...","TWN":"那個……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"제 짝사랑의 끝은 언제나 이런 식이었어요.","JPN":"私の片思いの終わりはいつもこんな感じでした。","ENG":"It’s been always like this.","TWN":"我每次單戀都是這種結局。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"먼저 고백을 하면, 상대는 서로에게 상처되기 싫다는 듯 거절을 에둘러 표현하고…….","JPN":"先に告白すると、相手はお互いに傷つきたくないと、遠回しに断って……","ENG":"When I confess my love, they make all kinds of excuses to turn me down.","TWN":"我先告白後，對方就會用不想彼此傷害的藉口拒絕我……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저도 진실을 그 입으로 직접 듣는 게 두려워서 늘 알겠다고만 했죠.","JPN":"私も真実を本人の口から直接聞くのが怖くて、いつもわかったと答えるだけでした。","ENG":"And I always say I understand, because I don’t want to hear a straightforward refusal.","TWN":"而我每次聽完也就不再說什麼，因為我也害怕從對方口中聽到真相。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하지만 이제 그런 건 지긋지긋해요.","JPN":"でも、もうそんなのはうんざりです。","ENG":"But not anymore.","TWN":"但我不想再這樣下去了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"날 좋아하지 않는 사람에게서 있지도 않는 희망을 붙잡는 건 정말 싫다고요!","JPN":"私のことを好きでもない人に希望を抱くのは本当に嫌です！","ENG":"I don’t want to hope in vain for a man who doesn’t love me!","TWN":"我不想再對一個不喜歡我的人懷抱希望！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그러니, 그 마음을 솔직하게 알려주세요! 선배!","JPN":"だから、その気持ちを素直に教えてください！　先輩！","ENG":"Tell me how you feel, Dark!","TWN":"所以請前輩老實地告訴我你的心意吧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"난 후배님을 좋아한다네.","JPN":"私は後輩くんが好きだ。","ENG":"I like you, Lone.","TWN":"我喜歡隆利啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"후배님의 어설픈 악의, 서투른 호의, 그리고 나만을 위해 만든 초콜릿까지. 전부 좋아하지.","JPN":"君の不器用な悪意、不器用な好意、そして私だけのために作ったチョコレートまで。全部好きだ。","ENG":"I like your clumsy malice, awkward goodwill, and the chocolate you made for me. I like everything about you.","TWN":"無論是你笨拙的好意…不加修飾壞意，或是為我而做的巧克力，我全都喜歡。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그렇기에 난 그 호의가 희생으로 이어지지 않았으면 좋겠다네.","JPN":"だから私はその好意が犠牲にならないでほしい。","ENG":"And I sincerely hope that you don’t sacrifice yourself for me.","TWN":"所以我不想浪費你的好意。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"자네라면 정말로 날 위해 지옥까지 뛰어들 테니까.","JPN":"君なら本当に私のために、地獄にすら飛び込むだろうからな。","ENG":"Because I know that you will go through hell just for me.","TWN":"因為我知道你真的會為我下地獄。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그러니 이것 하나만은 약속하지.","JPN":"だからこれだけは約束するよ。","ENG":"But let me promise you one thing.","TWN":"我只能答應你，"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이 모든 싸움이 끝나고 평화가 찾아온다면…….","JPN":"このすべての戦いが終わって平和が訪れたら……","ENG":"When all this fight is over and peace returns...","TWN":"當一切的戰爭結束，和平的日子來臨後……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그땐 내가 먼저 후배님을 찾아갈 거라고 말이야.","JPN":"その時は私が先に後輩くんのところへ会いに行くと。","ENG":"I’ll find you.","TWN":"到時我會第一個去找你。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님은 저에게 별이예요.","JPN":"先輩は私にとっての星です。","ENG":"You are my star, Dark.","TWN":"前輩對我而言就像天邊的星星。"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"화려하게 빛나지만, 손을 뻗어도 닿지 않는 별.","JPN":"華麗に輝くけど、手を伸ばしても届かない星。","ENG":"A shining star that I can never reach, no matter how hard I try.","TWN":"那麼地耀眼，卻又觸碰不到。"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"곁에 두고 싶지만…… 별이기 때문에 동경할 수밖에 없는 거겠죠.","JPN":"そばにいてほしいのに……星だからこそ、憧れるしかないのでしょう。","ENG":"Something that I want to keep... but I can never have.","TWN":"雖然很想待在前輩身邊……但星星是只可遠觀的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"실망시켜 미안하군.","JPN":"失望させてすまない。","ENG":"I’m sorry to let you down.","TWN":"很抱歉讓你失望了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후, 걱정하지 마세요. 대답은 충분히 들었으니까.","JPN":"ふふ、心配しないでください。答えは十分に聞けました。","ENG":"Hah hah. Don’t worry about it. Your answer was enough for me.","TWN":"呵呵，沒關係，起碼我有聽到答案。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"전 어미를 쫓는 아기새가 아니라, 선배님의 모든 것을 존경하는 충실한 후배니까요.","JPN":"私は親鳥を追う小鳥ではなく、先輩のすべてを尊敬する忠実な後輩ですから。","ENG":"I’m not a little bird leaning on you, but a junior who looks upon you.","TWN":"我不是跟在母雞後面的小雞，而是全心全意尊敬前輩的後輩。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_B"},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하지만 오늘밤은…… 이렇게 기대어 있고 싶어요.","JPN":"でも今夜は……こうやって寄りかかっていたいです。","ENG":"But just for today... I want to lean on your shoulder.","TWN":"今晚……我想就這樣靠著前輩，"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그래도 괜찮겠죠?","JPN":"それでも大丈夫ですよね？","ENG":"Is that okay with you?","TWN":"可以嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"물론일세.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"當然可以！"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"진정한 악당은 오늘을 즐기는 법이지.","JPN":"真の悪党なら、今存在しているこの時間を楽しまないと。","ENG":"A true villain knows how to enjoy their day.","TWN":"人生得意須盡歡。"},"stage":{"bg":"SKY_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"……그리고 난 아직 유부남이 아니라네.","JPN":"……そして、私はまだ既婚者ではない。","ENG":"... Also, I’m not married yet.","TWN":"……而且我又不是有婦之夫。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_CARTOON_03"},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"좋아해요, 선배님.","JPN":"好きです、先輩。","ENG":"I like you, Dark.","TWN":"前輩，我喜歡你。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};